 34→// validate checks that the required fields are present and within size limits.
 35→func validate(input SubmitInput) error {
 36→	if input.Subject == "" {
 37→		return fmt.Errorf("feedback: subject is required")
 38→	}
 39→	if len(input.Subject) > 200 {
 40→		return fmt.Errorf("feedback: subject exceeds 200 characters")
 41→	}
 42→	if input.Description == "" {
 43→		return fmt.Errorf("feedback: description is required")
 44→	}
 45→	if len(input.Description) > 5000 {
 46→		return fmt.Errorf("feedback: description exceeds 5000 characters")
 47→	}
 48→	return nil
 49→}
 50→
 51→// Submit validates and persists a feedback submission. Returns the generated ID.
 52→func (s *Service) Submit(ctx context.Context, input SubmitInput) (string, error) {
 53→	if err := validate(input); err != nil {
 54→		return "", err
 55→	}
 56→
 57→	id, err := newUUID()
 58→	if err != nil {
 59→		return "", fmt.Errorf("feedback: generate id: %w", err)
 60→	}
 61→
 62→	data := map[string]string{
 63→		"category":    input.Category,
 64→		"subject":     input.Subject,
 65→		"description": input.Description,
 66→	}
 67→	if input.UserAgent != "" {
 68→		data["userAgent"] = input.UserAgent
 69→	}
 70→	if input.PageURL != "" {
 71→		data["pageUrl"] = input.PageURL
 72→	}
 73→
 74→	dataJSON, err := json.Marshal(data)
 75→	if err != nil {
 76→		return "", fmt.Errorf("feedback: marshal data: %w", err)
 77→	}
 78→
 79→	// Determine user email: prefer JWT email, fall back to input email.
 80→	email := input.UserEmail
 81→	if email == "" {
 82→		email = input.Email
 83→	}
 84→
 85→	// Use nil for empty optional strings so the DB stores NULL.
 86→	var userID *string
 87→	if input.UserID != "" {
 88→		userID = &input.UserID
 89→	}
 90→	var userEmail *string
 91→	if email != "" {
 92→		userEmail = &email
 93→	}
 94→
 95→	var returnedID string
 96→	err = s.pool.QueryRow(ctx,
 97→		`INSERT INTO internal.user_feedback (id, user_id, user_email, data)
 98→		 VALUES ($1, $2, $3, $4)
 99→		 RETURNING id`,
100→		id, userID, userEmail, dataJSON,
101→	).Scan(&returnedID)
102→	if err != nil {
103→		return "", fmt.Errorf("feedback: insert: %w", err)
104→	}
105→
106→	return returnedID, nil
107→}
