109→// newUUID generates a UUID v4 string using crypto/rand.
110→func newUUID() (string, error) {
111→	var b [16]byte
112→	if _, err := rand.Read(b[:]); err != nil {
113→		return "", err
114→	}
115→	// Set version 4 and variant bits per RFC 4122.
116→	b[6] = (b[6] & 0x0f) | 0x40
117→	b[8] = (b[8] & 0x3f) | 0x80
118→	return fmt.Sprintf("%08x-%04x-%04x-%04x-%012x",
119→		b[0:4], b[4:6], b[6:8], b[8:10], b[10:16]), nil
120→}
