 57→// HMACValidator validates HS256 tokens using a shared secret.
 58→type HMACValidator struct {
 59→	secret     []byte
 60→	parserOpts []jwt.ParserOption
 61→}
 62→
 63→// NewHMACValidator creates a Validator using HS256 with the provided secret.
 64→// It returns an error if the secret is empty or contains only whitespace.
 65→func NewHMACValidator(secret string, opts ...jwt.ParserOption) (*HMACValidator, error) {
 66→	if strings.TrimSpace(secret) == "" {
 67→		return nil, errors.New("auth: HMAC secret must not be empty or whitespace-only")
 68→	}
 69→	return &HMACValidator{
 70→		secret:     []byte(secret),
 71→		parserOpts: opts,
 72→	}, nil
 73→}
 74→
 75→// Validate parses and validates an HS256 JWT token string.
 76→func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
 77→	claims := &Claims{}
 78→	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
 79→		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
 80→			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
 81→		}
 82→		return v.secret, nil
 83→	}, v.parserOpts...)
 84→	if err != nil {
 85→		return nil, fmt.Errorf("auth: token validation failed: %w", err)
 86→	}
 87→	if !token.Valid {
 88→		return nil, errors.New("auth: token is not valid")
 89→	}
 90→	return claims, nil
 91→}
